<?phpnamespace App\Controller;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;class AppController extends AbstractController{    /**     * @Route("/", name="app.home")     */    public function index(): Response    {        return $this->render('home.html.twig');    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/application-setting", name="super_admin.application_setting")     */    public function kohUtilisateurDashboard(): Response    {        return $this->render('application/application_setting.html.twig');    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/home", name="super_admin.home", methods={"GET"})     * @return Response     */    public function kohUtilisateurHome(): Response    {        return $this->render('application/home_koh_utilisateur.html.twig');    }    /**     * @Security("is_granted('ROLE_ADMIN') and user.getIsActived() and not user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/admin/home", name="admin_structure.home", methods={"GET"})     * @return Response     */    public function userStructureHome(): Response    {        return $this->render('application/home_koh_client_structure.html.twig');    }    /**     * @Security("is_granted('ROLE_ADMIN') and user.getIsActived() and not user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/admin/particulier/home", name="admin_particulier.home", methods={"GET"})     * @return Response     */    public function userParticulierHome(): Response    {        return $this->render('application/home_koh_client_particulier.html.twig');    }    /**     * @Route("/utilisateur/erreur-compte-utilisateur", name="app_error_account")     * @return Response     */    public function route_non_autorise(): Response    {        if ($this->getUser()->hasValideSuperAdminCompte() || $this->getUser()->hasValideAdminCompte()) {            return $this->redirectToRoute('app.home');        }                return $this->render('bundles/TwigBundle/Exception/inactifAccount.html.twig', [            'message' => 'Votre compte n\'est pas actif ou n\'est pas confirmé, Veuillez contactez un administrateur'        ]);    }}